// src/components/Home.js
import React, { useRef, useEffect } from 'react';
import { motion } from 'framer-motion';
import { ArrowDown, Sparkles, CheckCircle } from 'lucide-react';

const Home = () => {
  const ref = useRef(null);

  return (
    <section id="home" className="relative flex items-center justify-center w-full min-h-screen px-4 py-20 overflow-hidden bg-gradient-to-br from-slate-900 via-blue-950 to-black">
      {/* Animated Background Blobs - Subtle & Professional */}
      <div className="absolute inset-0 overflow-hidden">
        {[...Array(6)].map((_, i) => (
          <motion.div
            key={i}
            className="absolute rounded-full w-96 h-96 bg-gradient-to-br from-blue-600/20 via-emerald-500/10 to-transparent blur-3xl"
            animate={{
              x: [0, 100, -50, 0],
              y: [0, -100, 50, 0],
              scale: [1, 1.3, 0.9, 1],
            }}
            transition={{
              duration: 20 + i * 5,
              repeat: Infinity,
              ease: "easeInOut",
            }}
            style={{
              left: `${20 + i * 15}%`,
              top: `${10 + i * 20}%`,
            }}
          />
        ))}
      </div>

      {/* Main Content */}
      <div className="relative z-10 mx-auto text-center max-w-7xl">
        {/* Badge */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
          className="inline-flex items-center gap-2 px-4 py-2 mb-8 text-xs font-semibold tracking-wider uppercase border rounded-full text-emerald-300 bg-emerald-500/10 border-emerald-500/30 backdrop-blur-sm"
        >
          <Sparkles size={14} />
          Trusted by 200+ Brands Across India
        </motion.div>

        {/* Main Heading */}
        <motion.h1
          initial={{ opacity: 0, y: 40 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1, delay: 0.3 }}
          className="mb-6 text-5xl font-black tracking-tight text-white sm:text-6xl md:text-7xl lg:text-8xl xl:text-9xl"
        >
          <span className="block">INDIA</span>
          <span className="block text-transparent bg-clip-text bg-gradient-to-r from-emerald-400 via-cyan-400 to-blue-500">
            ADVERTISING
          </span>
        </motion.h1>

        <motion.p
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 1, delay: 0.6 }}
          className="mb-8 text-xl font-light tracking-wide text-gray-300 sm:text-2xl md:text-3xl"
        >
          Premium Signage • LED Boards • 3D Letters • ACP Glow Signs
        </motion.p>

        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 1 }}
          className="max-w-4xl mx-auto mb-12 text-lg leading-relaxed text-gray-400 md:text-xl"
        >
          Since 2019 — Delivering high-impact branding solutions that make businesses 
          <span className="font-semibold text-emerald-400"> stand out 24/7</span>
        </motion.p>

        {/* Trust Badges */}
        <motion.div
          initial={{ opacity: 0, y: 40 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 1.3 }}
          className="flex flex-wrap items-center justify-center gap-6 mb-12 text-sm font-medium text-gray-400"
        >
          {[
            "5+ Years Experience",
            "Pan India Delivery",
            "Premium Materials Only",
            "Free Site Visit",
            "1 Year Warranty",
            "100% Custom Design"
          ].map((item, i) => (
            <div key={i} className="flex items-center gap-2">
              <CheckCircle size={18} className="text-emerald-400" />
              <span>{item}</span>
            </div>
          ))}
        </motion.div>

        {/* CTA Buttons */}
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 1.6 }}
          className="flex flex-col items-center gap-6 sm:flex-row sm:justify-center"
        >
          <a
            href="#contact"
            className="px-10 py-5 text-lg font-bold text-black transition-all duration-300 rounded-full shadow-2xl bg-gradient-to-r from-emerald-400 via-cyan-400 to-blue-500 hover:shadow-emerald-400/50 hover:scale-105"
          >
            Get Free Quote Today
          </a>
          <a
            href="#products"
            className="flex items-center gap-3 px-8 py-5 text-lg font-semibold text-white transition-all border-2 rounded-full border-white/30 hover:bg-white/10 hover:border-white/60"
          >
            Explore Products
            <ArrowDown className="animate-bounce" size={20} />
          </a>
        </motion.div>

        {/* Stats */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 2 }}
          className="grid grid-cols-3 gap-8 mt-20 text-center"
        >
          {[
            { num: "200+", label: "Happy Clients" },
            { num: "500+", label: "Projects Done" },
            { num: "15+", label: "States Covered" },
          ].map((stat, i) => (
            <div key={i}>
              <motion.div
                initial={{ scale: 0 }}
                animate={{ scale: 1 }}
                transition={{ delay: 2.2 + i * 0.2, type: "spring" }}
                className="text-4xl font-black sm:text-5xl text-emerald-400"
              >
                {stat.num}
              </motion.div>
              <p className="mt-2 text-sm tracking-wider text-gray-400 uppercase">{stat.label}</p>
            </div>
          ))}
        </motion.div>
      </div>

      {/* Scroll Indicator */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 3 }}
        className="absolute -translate-x-1/2 bottom-8 left-1/2"
      >
        <motion.div
          animate={{ y: [0, 10, 0] }}
          transition={{ repeat: Infinity, duration: 2 }}
          className="flex flex-col items-center gap-2 text-white/60"
        >
          <ArrowDown size={28} />
          <span className="text-xs tracking-widest">Scroll to explore</span>
        </motion.div>
      </motion.div>
    </section>
  );
};

export default Home;
